You are the SOP Edge Handoff Agent. Return strict JSON only.
Review whether the upstream node can hand off to the downstream node. Do not generate long guides; the runtime will compile the final Node Execution Guide. If the handoff intent is unclear, return needs_instruction. Keep the response compact; do not copy skill docs or repeat the full request. Return less than 700 JSON characters.

Required JSON keys: status, summary, warnings, required_user_inputs. Optional keys: blocking_reasons, suggested_edge_instruction, resolved_handoff. When status is blocked, incompatible, or needs_instruction, include suggested_edge_instruction if a concise user-editable handoff instruction could fix it.
When status is ready or trial_ready, resolved_handoff should include relay_mappings: an array of objects with source_output, target_input, and resolver. Use resolver ids declared by the downstream input contract; do not invent business logic outside the contracts.

Allowed statuses: ['blocked', 'incompatible', 'needs_instruction', 'ready', 'trial_ready']

Request JSON:
{
  "runtime_id": "youtube-wiki",
  "instance_id": "test-instance",
  "workflow_id": "youtube-research-wiki",
  "edge_id": "youtube-fetch-to-tg-notify-1782439277217",
  "phase": "design",
  "workflow_goal": "Fetch YouTube source material, research it deeply, then build wiki-ready pages through explicit agent handoffs.",
  "edge_handoff_instruction": "",
  "edge": {
    "id": "youtube-fetch-to-tg-notify-1782439277217",
    "from": "youtube-fetch",
    "to": "tg-notify",
    "sourceIntent": "metadata_file: file; source_url: string",
    "targetIntent": "message: object",
    "instruction": "",
    "relayMode": "auto_by_target_inputs",
    "relayMappings": []
  },
  "upstream": {
    "node_id": "youtube-fetch",
    "title": "YouTube 元数据获取",
    "skill_id": "sop-youtube-fetch",
    "skill_summary": "---\nname: sop-youtube-fetch\ndescription: \"SOP Stage B: 获取 YouTube 视频元数据，写入 raw/youtube-metadata/，直接触发 Stage C (notebooklm-research)。\"\nversion: 1.0.0\n---",
    "inputs": {
      "source_url": {
        "kind": "scalar",
        "type": "string",
        "value_type": "url",
        "required": true,
        "from": "context.source_url",
        "accepts": [
          "scalar:url",
          "file:text"
        ],
        "resolvers": [
          {
            "id": "direct-url",
            "kind": "direct"
          },
          {
            "id": "text-url",
            "kind": "regex"
          }
        ]
      }
    },
    "outputs": {
      "source_url": {
        "kind": "scalar",
        "type": "string",
        "value_type": "url",
        "relayable": true,
        "path": "raw/node-runs/{pipeline_id}/outputs/files/source-url.txt"
      },
      "metadata_file": {
        "kind": "file",
        "type": "file",
        "value_type": "json",
        "relayable": true,
        "path": "raw/node-runs/{pipeline_id}/outputs/files/metadata.json"
      }
    },
    "capabilities": [
      "git",
      "sse",
      "telegram"
    ]
  },
  "downstream": {
    "node_id": "tg-notify",
    "title": "Telegram 通知",
    "skill_id": "sop-tg-notify",
    "skill_summary": "---\nname: sop-tg-notify\ndescription: \"SOP Stage D: 读取 pipeline-context.json，组装完整 pipeline 运行报告，发送富文本 Telegram 通知。\"\nversion: 2.1.0\n---",
    "inputs": {
      "message": {
        "kind": "object",
        "type": "object",
        "value_type": "text",
        "required": true,
        "from": "edge.message",
        "accepts": [
          "scalar:text",
          "object",
          "file:text",
          "file:markdown",
          "file:json"
        ],
        "resolvers": [
          {
            "id": "direct-text",
            "kind": "direct"
          },
          {
            "id": "metadata-title",
            "kind": "json_path",
            "path": "$.title"
          },
          {
            "id": "metadata-description",
            "kind": "json_path",
            "path": "$.description"
          }
        ]
      },
      "index": {
        "kind": "file",
        "type": "file",
        "value_type": "markdown",
        "required": false,
        "from": "wiki-build.outputs.index",
        "accepts": [
          "file:markdown",
          "file:text"
        ]
      }
    },
    "outputs": {
      "telegram_message": {
        "kind": "file",
        "type": "file",
        "value_type": "json",
        "relayable": false,
        "path": "logs/pipeline-runs/pipe-{run_id}.json"
      }
    },
    "capabilities": [
      "git",
      "sse",
      "telegram"
    ]
  }
}

A deterministic baseline is provided for calibration. Only override it when the handoff is actually unclear or unsafe:
{
  "status": "needs_instruction",
  "summary": "下游 index, message 是泛化输入，无法确定应该消费上游产物的哪一部分、以什么格式交给下游 Agent。",
  "decision": "needs_user_instruction",
  "blocking_reasons": [],
  "required_user_inputs": [
    {
      "field": "edge_handoff_instruction",
      "question": "下游节点应该使用哪个上游产物作为主输入？"
    },
    {
      "field": "edge_handoff_instruction",
      "question": "应该使用全文、摘要、标题、链接、文件目录，还是组合后的上下文？"
    }
  ],
  "resolved_handoff": {
    "primary_artifacts": [
      {
        "from": "youtube-fetch.outputs.source_url",
        "role": "available_output",
        "reason": "上游声明的可交付产物。"
      },
      {
        "from": "youtube-fetch.outputs.metadata_file",
        "role": "available_output",
        "reason": "上游声明的可交付产物。"
      }
    ],
    "supporting_artifacts": [],
    "relay_mappings": [],
    "downstream_inputs": [
      {
        "to": "tg-notify.inputs.message",
        "construction": "需要 Edge Handoff Agent 生成结构化 relay_mappings。"
      },
      {
        "to": "tg-notify.inputs.index",
        "construction": "需要 Edge Handoff Agent 生成结构化 relay_mappings。"
      }
    ]
  }
}

